import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, catchError, of, tap } from 'rxjs';

@Injectable({
  providedIn: 'root'
})
export class EmailVerificationService {
  private apiUrl = 'https://characters.discloud.app/api';

  constructor(private http: HttpClient) {}

  getUserVerificationStatus(): Observable<any> {
    const emailVerified = localStorage.getItem('email_verified') === 'true';
    const verificationMessage = localStorage.getItem('verification_message');
    const token = localStorage.getItem('auth_token');
    
    // Se já temos os dados salvos do login, usamos eles
    if (verificationMessage) {
      return new Observable(observer => {
        observer.next({
          emailVerified: emailVerified,
          verificationMessage: verificationMessage
        });
        observer.complete();
      });
    }
    
    // Caso contrário, tentamos buscar do servidor
    if (!token) return new Observable(observer => observer.next(null));
    
    return this.http.get(`${this.apiUrl}/user`, {
      headers: { Authorization: `Bearer ${token}` }
    }).pipe(
      catchError(error => {
        console.error('Erro ao verificar status do email:', error);
        return of({
          emailVerified: false,
          verificationMessage: 'Não foi possível verificar o status do seu email. Por favor, tente novamente mais tarde.'
        });
      })
    );
  }

  resendVerificationEmail(): Observable<any> {
    const userEmail = localStorage.getItem('user_email');
    const token = localStorage.getItem('auth_token');
    
    if (!userEmail) {
      console.error('Email não encontrado no localStorage');
      return new Observable(observer => {
        observer.error(new Error('Email do usuário não encontrado no armazenamento local'));
        observer.complete();
      });
    }

    if (!token) {
      console.error('Token não encontrado');
      return new Observable(observer => {
        observer.error(new Error('Token de autenticação não encontrado'));
        observer.complete();
      });
    }
    
    console.log('Enviando solicitação para reenviar email para:', userEmail);
    
    return this.http.post(`${this.apiUrl}/resend-verification`, 
      { email: userEmail },
      {
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        }
      }
    ).pipe(
      tap(response => console.log('Resposta do servidor:', response)),
      catchError(error => {
        console.error('Erro detalhado:', error);
        throw error;
      })
    );
  }
}
